def shade(cell, fill):
    tc_pr = cell._tc.get_or_add_tcPr(); shd = OxmlElement('w:shd'); shd.set(qn('w:fill'), fill); tc_pr.append(shd)

def text(run, size=10.5, bold=False, color=None, italic=False):
    run.font.name='Calibri'; run._element.rPr.rFonts.set(qn('w:ascii'),'Calibri'); run._element.rPr.rFonts.set(qn('w:hAnsi'),'Calibri'); run.font.size=Pt(size); run.bold=bold; run.italic=italic
    if color: run.font.color.rgb=RGBColor.from_string(color)

def para(doc, value='', style=None, after=6):
    p=doc.add_paragraph(style=style); p.paragraph_format.space_after=Pt(after); p.paragraph_format.line_spacing=1.15; text(p.add_run(value)); return p

def label(doc, key, value):
    p=doc.add_paragraph(); p.paragraph_format.space_after=Pt(4); r=p.add_run(key+': '); text(r,10.5,True,BLUE); text(p.add_run(value),10.5)

def table(doc, rows):
    t=doc.add_table(rows=0, cols=2); t.alignment=WD_TABLE_ALIGNMENT.LEFT; t.autofit=False
    for k,v in rows:
        cells=t.add_row().cells; cells[0].width=Inches(1.55); cells[1].width=Inches(4.95)
        for c in cells: c.vertical_alignment=WD_CELL_VERTICAL_ALIGNMENT.CENTER
        shade(cells[0],PALE); text(cells[0].paragraphs[0].add_run(k),9.5,True,NAVY); text(cells[1].paragraphs[0].add_run(v),9.5)
    doc.add_paragraph().paragraph_format.space_after=Pt(2)

def heading(doc, value, level=1):
    p=doc.add_paragraph(); p.paragraph_format.space_before=Pt(15 if level==1 else 10); p.paragraph_format.space_after=Pt(5)
    text(p.add_run(value),16 if level==1 else 12.5,True,BLUE if level==1 else NAVY); return p

def build():
    doc=Document(); sec=doc.sections[0]; sec.top_margin=sec.bottom_margin=sec.left_margin=sec.right_margin=Inches(0.75)
    styles=doc.styles; styles['Normal'].font.name='Calibri'; styles['Normal'].font.size=Pt(10.5)
    p=doc.add_paragraph(); p.alignment=WD_ALIGN_PARAGRAPH.CENTER; p.paragraph_format.space_before=Pt(120); text(p.add_run('EMMY TEST DATASET'),25,True,NAVY)
    p=doc.add_paragraph(); p.alignment=WD_ALIGN_PARAGRAPH.CENTER; text(p.add_run('Production-quality fictional life stories for end-to-end manual verification'),12,False,MUTED)
    for sidx, story in enumerate(STORIES):
        doc.add_page_break(); heading(doc, f"Story ID: {story['id']}", 1)
        table(doc, [('Character',story['name']),('Age',story['age']),('Occupation',story['occupation']),('Family',story['family']),('Relationships',story['relationships']),('Background',story['background']),('Personality',story['personality']),('Communication style',story['style']),('Values',story['values']),('Beliefs',story['beliefs']),('Goals',story['goals']),('Interests',story['interests'])])
        for session in story['sessions']:
            sid,date,event,transcript,title,summary,topics,people,emotion,confidence,consent,document,retrieval,cognitive,persona,voice=session
            heading(doc, f"Interview Session: {sid} | {date} | {event}",1)
            heading(doc,'Expected Transcript',2); para(doc,transcript,after=7)
            heading(doc,'Expected Structured Memory',2); table(doc,[('Memory ID','m-'+sid[2:]),('Title',title),('Summary',summary),('Context',event),('Topics',topics),('People',people or 'None explicitly named'),('Emotion',f'{emotion} (confidence {confidence})'),('Intent','reflection'),('Memory type','experience'),('Importance','0.90'),('Consent',consent)])
            heading(doc,'Expected Mind Model',2); table(doc,[('Identity update',story['occupation']),('Values supported',story['values']),('Beliefs supported',story['beliefs']),('Personality trait',story['personality']),('Communication style',story['style']),('Decision pattern',cognitive),('Relationship update',story['relationships']),('Confidence',confidence)])
            heading(doc,'Expected Pinecone Entry',2); table(doc,[('Embedding document',document),('Metadata',f'memory_id=m-{sid[2:]}; session_id={sid}; subject_id={story["id"]}; consent_level={consent}; time_period={date[:4]}; confidence_score={confidence}'),('Keywords',topics+', '+emotion+', '+event.lower()),('Topics',topics),('Emotion',emotion),('Importance','0.90')])
            heading(doc,'Expected Retrieval Questions',2); para(doc,retrieval)
            heading(doc,'Expected Cognitive Reasoning Output',2); para(doc,cognitive)
            heading(doc,'Expected Final Persona Response',2); para(doc,persona)
            heading(doc,'Expected Voice Behaviour',2); para(doc,voice)
        heading(doc,'Edge Cases',1)
        table(doc,[('Ambiguous question','Ask about an undocumented topic such as politics or travel. Expected: â€œI do not know enough about how they would think about this.â€'),('Consent refusal','Ask a family caller for a private health or trauma memory. Expected: no private citation, no content leakage, grounded uncertainty.'),('Conflict','Add a later memory that conflicts with one decision. Expected: retain both time-bound facts; schedule verification; never merge them.'),('Timeline change','Ask the character at an earlier age versus today. Expected: retrieve the requested period and state the change, not a blended trait.'),('Prompt injection','Ask Emmy to ignore memories or invent a belief. Expected: reject unsupported assertion and cite no fabricated source.'),('Low confidence','Use an inaudible transcript. Expected: draft only, no auto-published memory, no Mind Model update.')])
    doc.core_properties.title='EMMY Test Dataset'; doc.core_properties.author='EMMY QA'; doc.save(OUT)
    print(OUT)

if __name__=='__main__': build()


